#include <stdio.h>

// We add typedef at the start, and the shortcut name at the very end
typedef struct {
    int hp;
    int speed;
} Player;

int main() {
    // Now we can just say 'Player' instead of 'struct Player'!
    Player p1 = {100, 5};

    printf("HP: %d", p1.hp);
    return 0;
}

#include <stdio.h>
#include <string.h>

// A Union only reserves enough memory for its LARGEST member
union Box {
    int number;
    char text[20];
};

int main() {
    union Box myBox;

    myBox.number = 999;
    printf("Number is: %d\n", myBox.number); // Works fine

    // Using the text part overwrites the number!
    strcpy(myBox.text, "Hello World");
    printf("Text is: %s\n", myBox.text); 

    // The number is now corrupted memory garbage!
    printf("Number is now: %d\n", myBox.number); 
    return 0;
}
